    "km = range(2, 7)\n",
    "scores= []\n",
    "for k in km:\n",
    "    km = KMeans(n_clusters=k, n_init=20, random_state=42)\n",
    "    labels = km.fit_predict(X_ads_core)\n",
    "    score = silhouette_score(X_ads_core, labels)\n",
    "    scores.append(score)\n",
    "    print(f\"k={k}, silhouette={score:.3f}\")\n",
    "    \n",
    "plt.figure(figsize=(8,6))\n",
    "plt.plot(range(2, 7), scores)\n",
    "plt.xlabel(\"k\")\n",
