  {
   "cell_type": "code",
   "execution_count": null,
   "id": "d171711e",
   "metadata": {},
   "outputs": [],
   "source": [
    "import numpy as np\n",
    "import pandas as pd\n",
    "import matplotlib.pyplot as plt\n",
    "from math import pi\n",
    "from sklearn.preprocessing import MinMaxScaler\n",
    "\n",
    "def make_radar_chart(\n",
    "    df_profiles: pd.DataFrame,\n",
    "    features_to_plot: list,\n",
    "    title: str,\n",
    "    output_name: str,\n",
    "    *,\n",
    "    colors=None,\n",
    "    use_median: bool = False,\n",
    "    output_dir=None\n",
    "):\n",
    "    \"\"\"\n",
    "    df_profiles: rows = clusters, cols = features (already aggregated)\n",
    "    features_to_plot: list of feature columns\n",
    "    colors: dict {cluster_id: color} or list of colors\n",
    "    use_median: if True, assumes df_profiles already median; kept for clarity\n",
    "    output_dir: optional folder to save image\n",
    "    \"\"\"\n",
    "\n",
    "    # --- 1) Scale to [0, 1] for radar readability ---\n",
    "    scaler = MinMaxScaler()\n",
    "    scaled = scaler.fit_transform(df_profiles[features_to_plot])\n",
    "    df_scaled = pd.DataFrame(scaled, index=df_profiles.index, columns=features_to_plot)\n",
    "\n",
    "    # --- 2) Radar geometry ---\n",
    "    num_vars = len(features_to_plot)\n",
    "    angles = np.linspace(0, 2 * np.pi, num_vars, endpoint=False).tolist()\n",
    "    angles += angles[:1]  # close loop\n",
    "\n",
    "    fig, ax = plt.subplots(figsize=(10, 10), subplot_kw=dict(polar=True))\n",
    "\n",
    "    # --- 3) Stable colors ---\n",
    "    cluster_ids = list(df_scaled.index)\n",
    "\n",
    "    if colors is None:\n",
    "        raise ValueError(\"Please pass a palette_map for consistent cluster colouring.\")\n",
    "\n",
    "    color_map = colors\n",
    "\n",
    "    # --- 4) Plot each cluster ---\n",
    "    for cluster_id in cluster_ids:\n",
    "        values = df_scaled.loc[cluster_id].values.tolist()\n",
    "        values += values[:1]\n",
    "\n",
    "        is_zero = (cluster_id == 0) or (str(cluster_id) == \"0\")\n",
    "\n",
    "        ax.plot(\n",
    "            angles, values,\n",
    "            linewidth=4 if is_zero else 2,\n",
    "            linestyle='solid',\n",
    "            color=color_map[cluster_id],\n",
    "            zorder=10 if is_zero else 3,\n",
    "            label=f\"Cluster {cluster_id}\"\n",
    "        )\n",
    "\n",
    "    if not is_zero:\n",
    "        ax.fill(angles, values, alpha=0.12, color=color_map[cluster_id], zorder=2)\n",
    "\n",
    "    # --- 5) Labels / styling ---\n",
    "    ax.set_xticks(angles[:-1])\n",
    "    ax.set_xticklabels([f.replace(\"_\", \"\\n\") for f in features_to_plot], fontsize=9)\n",
    "\n",
    "    ax.set_yticks([0.2, 0.4, 0.6, 0.8])\n",
    "    ax.set_yticklabels([\"0.2\", \"0.4\", \"0.6\", \"0.8\"], fontsize=8)\n",
    "    ax.set_ylim(0, 1)\n",
    "\n",
    "    ax.set_title(title, fontsize=14, fontweight=\"bold\", y=1.08)\n",
    "    ax.legend(loc=\"upper right\", bbox_to_anchor=(1.25, 1.10), fontsize=10)\n",
    "\n",
    "    plt.tight_layout()\n",
    "\n",
    "    if output_dir is not None:\n",
    "        plt.savefig(f\"{output_dir}/{output_name}.png\", dpi=150, bbox_inches=\"tight\")\n",
    "\n",
    "    plt.show()"
   ]
  },
